import { bounds } from "../../config/index.js";
import type { Behavior } from "../../schemas/entities/index.js";
import {
  getTile,
  inBounds,
  isWalkableTile,
  Terrain,
  type Tile,
} from "../map/index.js";
import { path } from "../map/path.js";
import { createRng, type Rng } from "../rng/index.js";
import { resolveAttack } from "../systems/combat.js";
import { isStunned } from "../systems/status.js";
import type {
  EngineLogEventDataByType,
  EnemyEntityInstance,
  EntityId,
  GameState,
  Position,
  SerializableRecord,
} from "../state/index.js";
import {
  destinationForMove,
  gridFromState,
  MOVE_DIRECTIONS,
  type ActorTurnHook,
  type MoveDirection,
  type TurnEvent,
  type TurnHookResult,
  type TurnHooks,
} from "../turn/index.js";
import {
  atTether,
  distanceTo,
  guardPostFor,
  isPatrolEngaged,
  isTerritorialProvoked,
  patrolIndexFor,
  playerVisible,
  readWaypointList,
} from "./perception.js";

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly enemy_moved: {
      readonly actorId: EntityId;
      readonly from: Position;
      readonly to: Position;
      readonly direction: MoveDirection;
    };
    readonly enemy_waited: {
      readonly actorId: EntityId;
    };
  }
}

export type BehaviorAction =
  | {
      readonly kind: "wait";
    }
  | {
      readonly kind: "move";
      readonly direction: MoveDirection;
    }
  | {
      readonly kind: "attack";
      readonly targetId: EntityId | "player";
    };

const AI_RNG_STREAM_ID = "ai";
const ROOT_RNG_STREAM_ID = "root";
const UINT32_SIZE = 0x1_0000_0000;

const KEEP_RANGE_MIN = bounds.enemyDesign.behaviorVocabulary.parameters
  .keepRangeDistanceTiles.min;
const KEEP_RANGE_MAX = bounds.enemyDesign.behaviorVocabulary.parameters
  .keepRangeDistanceTiles.max;

type MutableRngContext = {
  readonly base: Rng;
  rng: Rng;
  initialDraws: number;
  drawsUsed: number;
};

export const evaluateBehaviors = (
  state: GameState,
  enemyId: EntityId,
  rng: Rng | AiRngContext = aiRngContextFor(state),
): BehaviorAction => {
  const enemy = state.entities[enemyId];
  const context = isAiRngContext(rng) ? rng : aiRngContextFor(state);

  if (enemy?.kind !== "enemy") {
    return { kind: "wait" };
  }

  for (const behavior of enemy.definition.behaviors) {
    if (!behaviorConditionFires(state, enemy, behavior)) {
      continue;
    }

    return evaluateBehavior(state, enemyId, behavior, context);
  }

  return { kind: "wait" };
};

export type AiRngContext = MutableRngContext;

export const evaluateBehavior = (
  state: GameState,
  enemyId: EntityId,
  behavior: Behavior,
  rng: AiRngContext,
): BehaviorAction => {
  switch (behavior.kind) {
    case "approach_melee":
      return evaluateApproachMelee(state, enemyId);
    case "keep_range":
      return evaluateKeepRange(state, enemyId, behavior.keepRange?.distanceTiles);
    case "flee_low_hp":
      return evaluateFleeLowHp(state, enemyId, rng);
    case "territorial":
      return evaluateTerritorial(
        state,
        enemyId,
        behavior.territorial?.radiusTiles ?? KEEP_RANGE_MIN,
      );
    case "guard":
      return evaluateGuard(state, enemyId, behavior.guard);
    case "patrol":
      return evaluatePatrol(state, enemyId);
    default:
      return { kind: "wait" };
  }
};

export const executeBehaviorAction = (
  state: GameState,
  enemyId: EntityId,
  action: BehaviorAction,
): TurnHookResult => {
  switch (action.kind) {
    case "wait":
      return {
        state,
        events: [enemyEvent(state, "enemy_waited", { actorId: enemyId })],
      };
    case "attack": {
      const attackResult = resolveAttack(state, enemyId, action.targetId);

      if ("illegal" in attackResult) {
        return executeBehaviorAction(state, enemyId, { kind: "wait" });
      }

      return attackResult;
    }
    case "move":
      return resolveEnemyMove(state, enemyId, action.direction);
  }
};

export const behaviorActorTurnHook: ActorTurnHook = ({ state, actor }) => {
  if (actor.kind !== "enemy") {
    return { state };
  }

  const enemy = state.entities[actor.id];

  if (enemy?.kind !== "enemy" || enemy.definition.behaviors.length === 0) {
    return { state };
  }

  if (isStunned(enemy.statuses)) {
    return executeBehaviorAction(state, actor.id, { kind: "wait" });
  }

  const rngContext = aiRngContextFor(state);
  const action = evaluateBehaviors(state, actor.id, rngContext);
  const result = executeBehaviorAction(state, actor.id, action);
  const nextState = withAiRngCursor(normalizeHookState(result), rngContext);

  return {
    state: nextState,
    events: normalizeHookEvents(result),
  };
};

export const behaviorTurnHooks = (): TurnHooks => ({
  actorTurn: behaviorActorTurnHook,
});

let registeredBehaviorActorTurnHook: ActorTurnHook | null = null;

export const registerBehaviorActorTurnHook = (): (() => void) => {
  const previous = registeredBehaviorActorTurnHook;
  registeredBehaviorActorTurnHook = behaviorActorTurnHook;

  return () => {
    if (registeredBehaviorActorTurnHook === behaviorActorTurnHook) {
      registeredBehaviorActorTurnHook = previous;
    }
  };
};

export const resolveRegisteredBehaviorActorTurnHook = (): ActorTurnHook =>
  registeredBehaviorActorTurnHook ?? behaviorActorTurnHook;

export const createAiRngContext = (state: GameState): AiRngContext =>
  aiRngContextFor(state);

export const behaviorConditionFires = (
  state: GameState,
  enemy: EnemyEntityInstance,
  behavior: Behavior,
): boolean => {
  switch (behavior.kind) {
    case "flee_low_hp": {
      const threshold = behavior.fleeLowHp?.thresholdPercent;

      if (threshold === undefined) {
        return false;
      }

      return (
        enemy.currentHP * 100 <=
        threshold * enemy.definition.stats.hp
      );
    }
    case "approach_melee":
    case "keep_range":
    case "territorial":
    case "guard":
    case "patrol":
      return true;
    default:
      return false;
  }
};

const evaluateApproachMelee = (
  state: GameState,
  enemyId: EntityId,
): BehaviorAction => {
  const enemy = state.entities[enemyId];

  if (enemy?.kind !== "enemy") {
    return { kind: "wait" };
  }

  if (isAdjacent(enemy.position, state.player.position)) {
    return { kind: "attack", targetId: "player" };
  }

  const approachGoal = approachGoalFor(state, enemyId);

  if (approachGoal === null) {
    return { kind: "wait" };
  }

  return stepToward(state, enemyId, approachGoal, {});
};

const evaluateKeepRange = (
  state: GameState,
  enemyId: EntityId,
  preferredDistance: number | undefined,
): BehaviorAction => {
  const distance = distanceTo(state, enemyId);

  if (distance >= KEEP_RANGE_MIN && distance <= KEEP_RANGE_MAX) {
    return { kind: "wait" };
  }

  if (distance < KEEP_RANGE_MIN) {
    return stepAwayFromPlayer(state, enemyId, {});
  }

  const approachGoal = approachGoalFor(state, enemyId);

  if (approachGoal === null) {
    return { kind: "wait" };
  }

  if (preferredDistance !== undefined && distance > preferredDistance) {
    return stepToward(state, enemyId, approachGoal, {});
  }

  return stepToward(state, enemyId, approachGoal, {});
};

const evaluateFleeLowHp = (
  state: GameState,
  enemyId: EntityId,
  rng: AiRngContext,
): BehaviorAction =>
  stepAwayFromPlayer(state, enemyId, { rng, maximizeDistance: true });

const evaluateTerritorial = (
  state: GameState,
  enemyId: EntityId,
  radiusTiles: number,
): BehaviorAction => {
  const enemy = state.entities[enemyId];

  if (enemy?.kind !== "enemy") {
    return { kind: "wait" };
  }

  const provoked = isTerritorialProvoked(enemy);
  const playerInside =
    playerVisible(state, enemyId) &&
    distanceTo(state, enemyId) <= radiusTiles;

  if (!provoked && !playerInside) {
    return { kind: "wait" };
  }

  return evaluateApproachMelee(state, enemyId);

import {
  canSee,
  chebyshevDistance,
  type TileGrid,
} from "../map/index.js";
import type {
  EnemyEntityInstance,
  EntityId,
  GameState,
  Position,
} from "../state/index.js";
import { gridFromState } from "../turn/actions.js";

/** LOS radius for enemy perception; map-sized default until a config pin exists. */
export const PERCEPTION_RADIUS_TILES = 99;

export const enemyEntity = (
  state: GameState,
  enemyId: EntityId,
): EnemyEntityInstance | null => {
  const entity = state.entities[enemyId];

  return entity?.kind === "enemy" ? entity : null;
};

export const gridOrNull = (state: GameState): TileGrid | null =>
  gridFromState(state);

export const playerVisible = (state: GameState, enemyId: EntityId): boolean => {
  const enemy = enemyEntity(state, enemyId);
  const grid = gridOrNull(state);

  if (enemy === null || grid === null) {
    return false;
  }

  return canSee(
    grid,
    enemy.position,
    state.player.position,
    PERCEPTION_RADIUS_TILES,
  );
};

export const distanceTo = (
  state: GameState,
  enemyId: EntityId,
  target: Position = state.player.position,
): number => {
  const enemy = enemyEntity(state, enemyId);

  if (enemy === null) {
    return Number.POSITIVE_INFINITY;
  }

  return chebyshevDistance(enemy.position, target);
};

export const hpFraction = (state: GameState, enemyId: EntityId): number => {
  const enemy = enemyEntity(state, enemyId);

  if (enemy === null) {
    return 1;
  }

  const maxHp = enemy.definition.stats.hp;

  if (maxHp <= 0) {
    return 0;
  }

  return enemy.currentHP / maxHp;
};

export const alliesWithTag = (
  state: GameState,
  enemyId: EntityId,
  inSight: boolean,
): readonly EnemyEntityInstance[] => {
  const enemy = enemyEntity(state, enemyId);

  if (enemy === null) {
    return [];
  }

  const tag = enemy.definition.origin;
  const allies = Object.values(state.entities).filter(
    (entity): entity is EnemyEntityInstance =>
      entity.kind === "enemy" &&
      entity.id !== enemyId &&
      entity.definition.origin === tag,
  );

  if (!inSight) {
    return allies;
  }

  return allies.filter((ally) => playerVisibleFrom(state, enemy.position, ally.position));
};

export const readPositionRecord = (
  value: unknown,
): Position | null => {
  if (typeof value !== "object" || value === null) {
    return null;
  }

  const record = value as { readonly x?: unknown; readonly y?: unknown };

  if (
    typeof record.x === "number" &&
    Number.isSafeInteger(record.x) &&
    typeof record.y === "number" &&
    Number.isSafeInteger(record.y)
  ) {
    return { x: record.x, y: record.y };
  }

  return null;
};

export const guardPostFor = (enemy: EnemyEntityInstance): Position =>
  readPositionRecord(enemy.behaviorRuntime.post) ?? enemy.position;

export const atTether = (
  state: GameState,
  enemyId: EntityId,
  post: Position,
  radiusTiles: number,
): boolean => distanceFromPost(state, enemyId, post) <= radiusTiles;

export const distanceFromPost = (
  state: GameState,
  enemyId: EntityId,
  post: Position,
): number => {
  const enemy = enemyEntity(state, enemyId);

  if (enemy === null) {
    return Number.POSITIVE_INFINITY;
  }

  return chebyshevDistance(enemy.position, post);
};

export const isTerritorialProvoked = (enemy: EnemyEntityInstance): boolean => {
  if (enemy.behaviorRuntime.provoked === true) {
    return true;
  }

  return enemy.currentHP < enemy.definition.stats.hp;
};

export const readWaypointList = (
  enemy: EnemyEntityInstance,
): readonly Position[] => {
  const raw = enemy.behaviorRuntime.waypoints;

  if (!Array.isArray(raw)) {
    return [];
  }

  const waypoints: Position[] = [];

  for (const entry of raw) {
    const position = readPositionRecord(entry);

    if (position !== null) {
      waypoints.push(position);
    }
  }

  return waypoints;
};

export const patrolIndexFor = (enemy: EnemyEntityInstance): number => {
  const raw = enemy.behaviorRuntime.patrolIndex;

  return typeof raw === "number" && Number.isSafeInteger(raw) && raw >= 0
    ? raw
    : 0;
};

export const isPatrolEngaged = (enemy: EnemyEntityInstance): boolean =>
  enemy.behaviorRuntime.patrolEngaged === true;

const playerVisibleFrom = (
