): void => {
  if (value < range.min) {
    ctx.addIssue({
      code: "custom",
      path,
      message: `must be at least ${range.min}`,
    });
  }

  if (value > range.max) {
    ctx.addIssue({
      code: "custom",
      path,
      message: `must be at most ${range.max}`,
    });
  }
};

